package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.internal.bind.JsonTreeWriter;
import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonTreeWriterTest {

  private JsonTreeWriter jsonTreeWriter;

  @BeforeEach
  public void setUp() {
    jsonTreeWriter = new JsonTreeWriter();
  }

  @Test
  public void testValue_withValidDouble_returnsThis() throws IOException {
    JsonWriter returned = jsonTreeWriter.value(123.456);
    assertSame(jsonTreeWriter, returned);
  }

  @Test
  public void testValue_withNaN_throwsIllegalArgumentException() {
    IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
      jsonTreeWriter.value(Double.NaN);
    });
    assertTrue(exception.getMessage().contains("NaN"));
  }

  @Test
  public void testValue_withPositiveInfinity_throwsIllegalArgumentException() {
    IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
      jsonTreeWriter.value(Double.POSITIVE_INFINITY);
    });
    assertTrue(exception.getMessage().contains("infinities"));
  }

  @Test
  public void testValue_withNegativeInfinity_throwsIllegalArgumentException() {
    IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
      jsonTreeWriter.value(Double.NEGATIVE_INFINITY);
    });
    assertTrue(exception.getMessage().contains("infinities"));
  }

  @Test
  public void testValue_allowsNaNWhenLenient() throws Exception {
    // Use reflection to set lenient to true
    Method setLenientMethod = JsonWriter.class.getDeclaredMethod("setLenient", boolean.class);
    setLenientMethod.setAccessible(true);
    setLenientMethod.invoke(jsonTreeWriter, true);

    // Should not throw with NaN now
    JsonWriter returned = jsonTreeWriter.value(Double.NaN);
    assertSame(jsonTreeWriter, returned);
  }

  @Test
  public void testPutCalledWithCorrectJsonPrimitive() throws Exception {
    // Spy on JsonTreeWriter to verify put is called via reflection
    JsonTreeWriter spyWriter = spy(jsonTreeWriter);

    double testValue = 42.0;
    spyWriter.value(testValue);

    // Use reflection to get the private put method
    Method putMethod = JsonTreeWriter.class.getDeclaredMethod("put", com.google.gson.JsonElement.class);
    putMethod.setAccessible(true);

    // Verify that put was called with the correct JsonPrimitive by checking the invocation on the spy
    // Mockito cannot verify private method calls directly, so we verify by intercepting the call via a spy
    // We do this by using Mockito's verify on the spy's put method via reflection

    // Instead, we manually verify by invoking put on spyWriter with an ArgumentCaptor-like approach:

    // Unfortunately, Mockito cannot verify private method calls directly.
    // So instead, we can use a workaround: override put method in a subclass to capture the argument.

    class JsonTreeWriterSubclass extends JsonTreeWriter {
      com.google.gson.JsonElement capturedArgument = null;
      @Override
      protected void put(com.google.gson.JsonElement value) {
        capturedArgument = value;
        super.put(value);
      }
    }

    JsonTreeWriterSubclass subclassWriter = spy(new JsonTreeWriterSubclass());
    subclassWriter.value(testValue);

    com.google.gson.JsonElement arg = subclassWriter.capturedArgument;
    assertNotNull(arg);
    assertTrue(arg instanceof JsonPrimitive);
    assertEquals(testValue, ((JsonPrimitive) arg).getAsDouble());
  }
}
